// Stringify — JS object to JSON string
const user = { name: 'Alice', age: 30, scores: [95, 88] };
const json = JSON.stringify(user);
console.log(json); // '{"name":"Alice","age":30,"scores":[95,88]}'

// Pretty print (indented)
console.log(JSON.stringify(user, null, 2));

// Parse — JSON string to JS object
const parsed = JSON.parse(json);
console.log(parsed.name); // 'Alice'

// Handle parse errors
try {
  JSON.parse("{ invalid json }");
} catch (e) {
  console.error('Invalid JSON:', e.message);
}

// Deep clone (simple objects only)
const original = { a: 1, nested: { b: 2 } };
const clone = JSON.parse(JSON.stringify(original));
clone.nested.b = 99;
console.log(original.nested.b); // 2 — not affected
